from typing import List

def unique_paths_with_obstacles(obstacle_grid: List[List[int]]) -> int:
    m, n = len(obstacle_grid), len(obstacle_grid[0])

    if obstacle_grid[0][0] == 1:
        return 0

    obstacle_grid[0][0] = 1

    for i in range(1, m):
        obstacle_grid[i][0] = 1 if obstacle_grid[i][0] == 0 and obstacle_grid[i - 1][0] == 1 else 0

    for j in range(1, n):
        obstacle_grid[0][j] = 1 if obstacle_grid[0][j] == 0 and obstacle_grid[0][j - 1] == 1 else 0

    for i in range(1, m):
        for j in range(1, n):
            if obstacle_grid[i][j] == 0:
                obstacle_grid[i][j] = obstacle_grid[i - 1][j] + obstacle_grid[i][j - 1]
            else:
                obstacle_grid[i][j] = 0

    return obstacle_grid[m - 1][n - 1]
